create table notebook_volumes
(
    id          bigint unsigned auto_increment
        primary key,
    created_at  datetime(3)     null,
    updated_at  datetime(3)     null,
    deleted_at  datetime(3)     null,
    notebook_id bigint unsigned null comment 'Notebook ID',
    name        varchar(191)    null comment '卷名称',
    mounts_path varchar(191)    null comment '挂载路径',
    size        bigint          null comment '大小',
    type        varchar(191)    null comment '类型(dataset/model/workspace)',
    pvc_id      bigint unsigned null comment 'PVC ID',
    pvc_name    varchar(191)    null comment 'PVC名称'
);

create index idx_notebook_volumes_deleted_at
    on notebook_volumes (deleted_at);

create index idx_notebook_volumes_notebook_id
    on notebook_volumes (notebook_id);

